// Script: generar_156_racha_registros.js
// Racha de registros diarios con Chiqui cool.
// En los hitos 3, 5, 7, 14 y 30 dias consecutivos aparece un banner
// con chiqui_cool.png y un mensaje celebratorio.
// Incluye tambien el fix del modal de peso (PesoTracker).

const fs = require('fs'); const path = require('path');
function png(r, b64) {
  const f = path.join(...r.split('/')); const d = path.dirname(f);
  if (!fs.existsSync(d)) fs.mkdirSync(d,{recursive:true});
  fs.writeFileSync(f, Buffer.from(b64,'base64')); console.log('OK: '+f);
}
function tsx(r, b64) {
  const f = path.join(...r.split('/')); const d = path.dirname(f);
  if (!fs.existsSync(d)) fs.mkdirSync(d,{recursive:true});
  fs.writeFileSync(f, Buffer.from(b64,'base64').toString('utf8')); console.log('OK: '+f);
}
png('public/chiqui/chiqui_ladeado.png', "");
tsx('app/dashboard/page.tsx', "");
tsx('components/DashboardContenido.tsx', "");
tsx('components/PesoTracker.tsx', "");
